// Script Continued Below
// KT - REQUEST TYPE
function onSubmit() {

	var table = 'x_153465_discovert_tasker_requests';
	var RequestSysId; 
	var modalForm;
	// STRY0103010, STRY0102985, STRY0101757, STRY0104533
	var title;
	var view;
	var isRequest;
	var parent;
	var request_type;

	var formAction = g_form.getActionName();

	// STRY0088787 added if statement to check the submit is a Request submit, then doin save before continuing
	if((formAction == 'openModalRespondClarificationSP')
		|| (formAction == 'openModalRequestClarificationSP')
		|| (formAction == 'openModalRespondExtensionSP')
		|| (formAction == 'openModalRequestExtensionSP')
		|| (formAction == 'openModalRespondReassignmentSP')
		|| (formAction == 'openModalRequestReassignmentSP')
		){
		// If the form is dirty, ask the user if they would like to save the record
		var saveChangeConfirmation = false;
		var saveMsg = getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				var fMsg = changeFieldList.join(', ');					
				saveMsg += "  " + fMsg;
				saveChangeConfirmation = true;
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			saveMsg += JSON.stringify(g_form.modifiedFields);
			saveChangeConfirmation = true;
		}

		// use the variable set above here to show confirmation message.
		if(saveChangeConfirmation){				
			if(confirm(saveMsg)){
				g_form.save();
			} else{
				return false;
			}
		}
		// STRY0103010, STRY0102985, STRY0101757, STRY0104533
		// set the varialbes to use in the modal calls below
		switch(formAction){
			case 'openModalRequestClarificationSP':
				title = getMessage('Tasker - Title - Request Clarification');
				view = 'requesttop';
				isRequest = true;
				parent = g_form.getUniqueValue();
				request_type = 'Clarification';
				break;
			case 'openModalRespondClarificationSP':
				title = getMessage('Tasker - Title - Respond Clarification Request');
				view = 'responsetop';
				isRequest = false;
				parent = '';
				request_type = 'Clarification';
				break;
			case 'openModalRequestExtensionSP':
				title = getMessage('Tasker - Title - Request Extension');
				view = 'requesttop';
				isRequest = true;
				parent = g_form.getUniqueValue();
				request_type = 'Extension';
				break;
			case 'openModalRespondExtensionSP':
				title = getMessage('Tasker - Title - Respond Extension Request');
				view = 'responsetop';
				isRequest = false;
				parent = '';
				request_type = 'Extension';
				break;
			case 'openModalRequestReassignmentSP':
				title = getMessage('Tasker - Title - Request Reassignment');
				view = 'requesttop';
				isRequest = true;
				parent = g_form.getUniqueValue();
				request_type = 'Reassignment';
				break;
			case 'openModalRespondReassignmentSP':
				title = getMessage('Tasker - Title - Respond Reassignment Request');
				view = 'responsetop';
				isRequest = false;
				parent = '';
				request_type = 'Reassignment';
				break;
		}

		if(isRequest){
			openRequestModal();
		} else {
			getRequestSysId(request_type);
		}
		return false;		
	}


	// STRY0103010, STRY0102985, STRY0101757, STRY0104533
	// Open the modal, will be called after the call back to get the ID or directly from the form action switch
	function openRequestModal(){
		var oWidgetInput = {};
		if (typeof spModal != 'undefined' ) { 
			if(isRequest){
				// DFCT0010643
				oWidgetInput = {table: table, sys_id: -1, view: view, parent:parent, u_request_type: request_type, isModal: true, omitHeader: 'true'};
			} else {
				oWidgetInput = {table: table, sys_id: RequestSysId, view:view, isModal: true};
			}
			spModal.open({
				title:  title,
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: oWidgetInput,
				size:'lg',
				buttons: []
			});
		} else {
			modalForm = new GlideModalForm(title, table);
			if(isRequest){
				modalForm.addParm('sysparm_query','parent='+parent + '^u_request_type=' + request_type);
			} else {
				// STRY0103010 - set the ID before render
				modalForm.setSysID(RequestSysId);
			}
			modalForm.addParm('sysparm_view', view); //Specify a form view
			modalForm.render();
			if(isRequest){
				modalForm.setSysID(-1);
			}

			modalForm.setCompletionCallback(refreshForm);
		}
	}

	// STRY0103010, STRY0102985, STRY0101757, STRY0104533
	// this is called from the Open Modal callback to refresh the form
	function refreshForm() {
		g_form.save();
	}	

	//-----------------------------------------------------------------------------------------------------------------	
	function getRequestSysId(SelectedRequestType){
			var ga = new GlideAjax("ClientTaskRequest");
			ga.addParam('sysparm_name', 'getRequestIdToOpen');
			ga.addParam('pTaskSysId', g_form.getUniqueValue());
			ga.addParam('pRequestType', SelectedRequestType);
			ga.addParam('pStatus', 'In Progress');

			ga.getXML(getRequestSysId, null);

			function getRequestSysId(response){
				var answer = response.responseXML.documentElement.getAttribute("answer");
				RequestSysId = answer;
				// STRY0103010, STRY0102985, STRY0101757, STRY0104533
				openRequestModal();
			}
	}

}
